import { useEffect, useRef } from 'react';
import * as THREE from 'three';

export default function HeroThreeScene() {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const W = mount.clientWidth;
    const H = mount.clientHeight;

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(60, W / H, 0.1, 100);
    camera.position.set(0, 0, 8);

    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
    renderer.setSize(W, H);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setClearColor(0x000000, 0);
    mount.appendChild(renderer.domElement);

    // Ambient light
    scene.add(new THREE.AmbientLight(0xffffff, 0.3));
    const redLight = new THREE.PointLight(0xe50914, 3, 20);
    redLight.position.set(-5, 3, 5);
    scene.add(redLight);
    const blueLight = new THREE.PointLight(0x4466ff, 2, 20);
    blueLight.position.set(5, -3, 5);
    scene.add(blueLight);

    const objects = [];

    // Create torus rings (film reel aesthetic)
    for (let i = 0; i < 3; i++) {
      const geo = new THREE.TorusGeometry(1.5 + i * 0.6, 0.04, 8, 64);
      const mat = new THREE.MeshStandardMaterial({
        color: i === 0 ? 0xe50914 : i === 1 ? 0x4466ff : 0xffffff,
        emissive: i === 0 ? 0x660000 : i === 1 ? 0x002244 : 0x111111,
        metalness: 0.8, roughness: 0.2, transparent: true, opacity: 0.7
      });
      const torus = new THREE.Mesh(geo, mat);
      torus.rotation.x = Math.PI / 4 + i * 0.3;
      torus.rotation.y = i * 0.5;
      scene.add(torus);
      objects.push({ mesh: torus, speed: 0.003 + i * 0.002, axis: i % 2 === 0 ? 'x' : 'y' });
    }

    // Central glowing sphere
    const sphereGeo = new THREE.SphereGeometry(0.5, 32, 32);
    const sphereMat = new THREE.MeshStandardMaterial({
      color: 0xe50914, emissive: 0xe50914, emissiveIntensity: 0.8,
      metalness: 1, roughness: 0, transparent: true, opacity: 0.9
    });
    const sphere = new THREE.Mesh(sphereGeo, sphereMat);
    scene.add(sphere);

    // Floating cubes
    for (let i = 0; i < 15; i++) {
      const size = 0.05 + Math.random() * 0.15;
      const geo = new THREE.BoxGeometry(size, size, size);
      const mat = new THREE.MeshStandardMaterial({
        color: Math.random() > 0.5 ? 0xe50914 : 0x4466ff,
        emissive: Math.random() > 0.5 ? 0x440000 : 0x001133,
        metalness: 0.9, roughness: 0.1, transparent: true, opacity: 0.6
      });
      const cube = new THREE.Mesh(geo, mat);
      cube.position.set((Math.random() - 0.5) * 12, (Math.random() - 0.5) * 8, (Math.random() - 0.5) * 4);
      cube.userData = {
        vx: (Math.random() - 0.5) * 0.005,
        vy: (Math.random() - 0.5) * 0.005,
        rx: Math.random() * 0.02,
        ry: Math.random() * 0.02
      };
      scene.add(cube);
      objects.push({ mesh: cube, isCube: true });
    }

    // Particle trail
    const trailGeo = new THREE.BufferGeometry();
    const count = 500;
    const pos = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 20;
      pos[i * 3 + 1] = (Math.random() - 0.5) * 12;
      pos[i * 3 + 2] = (Math.random() - 0.5) * 8 - 2;
    }
    trailGeo.setAttribute('position', new THREE.BufferAttribute(pos, 3));
    const trailMat = new THREE.PointsMaterial({ size: 0.03, color: 0xe50914, transparent: true, opacity: 0.4 });
    const trail = new THREE.Points(trailGeo, trailMat);
    scene.add(trail);

    // Mouse interaction
    const mouse = { x: 0, y: 0 };
    const handleMouse = (e) => {
      mouse.x = (e.clientX / window.innerWidth) * 2 - 1;
      mouse.y = -(e.clientY / window.innerHeight) * 2 + 1;
    };
    window.addEventListener('mousemove', handleMouse);

    let t = 0;
    let animId;
    const animate = () => {
      animId = requestAnimationFrame(animate);
      t += 0.01;

      // Rotate rings
      objects.forEach(obj => {
        if (!obj.isCube) {
          obj.mesh.rotation.x += obj.speed * 0.8;
          obj.mesh.rotation.y += obj.speed;
        } else {
          obj.mesh.position.x += obj.mesh.userData.vx;
          obj.mesh.position.y += obj.mesh.userData.vy;
          obj.mesh.rotation.x += obj.mesh.userData.rx;
          obj.mesh.rotation.y += obj.mesh.userData.ry;
          if (Math.abs(obj.mesh.position.x) > 7) obj.mesh.userData.vx *= -1;
          if (Math.abs(obj.mesh.position.y) > 5) obj.mesh.userData.vy *= -1;
        }
      });

      // Pulse sphere
      const scale = 1 + Math.sin(t * 2) * 0.15;
      sphere.scale.set(scale, scale, scale);
      sphereMat.emissiveIntensity = 0.5 + Math.sin(t * 3) * 0.3;

      // Mouse parallax
      camera.position.x += (mouse.x * 0.5 - camera.position.x) * 0.05;
      camera.position.y += (mouse.y * 0.3 - camera.position.y) * 0.05;
      camera.lookAt(0, 0, 0);

      // Animate lights
      redLight.position.x = Math.sin(t * 0.5) * 5;
      blueLight.position.x = -Math.sin(t * 0.5) * 5;

      // Scroll trail
      const p = trailGeo.attributes.position.array;
      for (let i = 0; i < count; i++) {
        p[i * 3 + 2] += 0.01;
        if (p[i * 3 + 2] > 5) p[i * 3 + 2] = -8;
      }
      trailGeo.attributes.position.needsUpdate = true;

      renderer.render(scene, camera);
    };
    animate();

    const handleResize = () => {
      if (!mount) return;
      camera.aspect = mount.clientWidth / mount.clientHeight;
      camera.updateProjectionMatrix();
      renderer.setSize(mount.clientWidth, mount.clientHeight);
    };
    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener('mousemove', handleMouse);
      window.removeEventListener('resize', handleResize);
      renderer.dispose();
      if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
    };
  }, []);

  return <div ref={mountRef} style={{ width: '100%', height: '100%' }} />;
}
